import org.eclipse.rdf4j.query.algebra.evaluation.QueryOptimizerTest;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.QueryModelNormalizerOptimizer;
import org.eclipse.rdf4j.query.parser.ParsedTupleQuery;
import org.eclipse.rdf4j.query.parser.QueryParserUtil;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class QueryModelNormalizerTest extends QueryOptimizerTest {

	private QueryModelNormalizerOptimizer subject;

	@BeforeEach
	public void setup() {
		subject = getOptimizer();
	}

	@Test
	public void testNormalizeUnionWithEmptyLeft() {
		Projection p = new Projection();
		Union union = new Union();
		SingletonSet s = new SingletonSet();
		union.setLeftArg(new EmptySet());
		union.setRightArg(s);
		p.setArg(union);

		subject.meet(union);

		assertThat(p.getArg()).isEqualTo(s);
	}

	@Test
	public void testNormalizeUnionWithEmptyRight() {
		Projection p = new Projection();
		Union union = new Union();
		SingletonSet s = new SingletonSet();
		union.setRightArg(new EmptySet());
		union.setLeftArg(s);
		p.setArg(union);

		subject.meet(union);

		assertThat(p.getArg()).isEqualTo(s);
	}

	/**
	 * @see <a href="https://github.com/eclipse/rdf4j/issues/1404">GH-1404</a>
	 */
	@Test
	public void testNormalizeUnionWithTwoSingletons() {
		Projection p = new Projection();
		Union union = new Union();
		union.setRightArg(new SingletonSet());
		union.setLeftArg(new SingletonSet());
		p.setArg(union);

		subject.meet(union);

		assertThat(p.getArg()).isEqualTo(union);
	}

	@Test
	public void testQueryLevelValuesStayOutsideUnion() {
		String query = String.join("\n",
				"PREFIX : <http://example.com/>",
				"SELECT ?s ?x ?n WHERE {",
				"  { ?s a :T OPTIONAL { ?s :note ?n } MINUS { ?u :u ?x } } UNION { ?s :q ?o }",
				"}",
				"VALUES ?x { 1 }");

		ParsedTupleQuery parsedQuery = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, query, null);
		subject.optimize(parsedQuery.getTupleExpr(), null, null);

		Join join = findTopLevelJoin(parsedQuery.getTupleExpr());
		assertThat(join.isVariableScopeChange()).isTrue();
		assertThat(join.getLeftArg()).isInstanceOf(Union.class);
		assertThat(join.getRightArg()).isInstanceOf(BindingSetAssignment.class);
	}

	@Override
	public QueryModelNormalizerOptimizer getOptimizer() {
		return new QueryModelNormalizerOptimizer();
	}

	private Join findTopLevelJoin(TupleExpr tupleExpr) {
		while (!(tupleExpr instanceof Join)) {
			assertThat(tupleExpr).isInstanceOf(UnaryTupleOperator.class);
			tupleExpr = ((UnaryTupleOperator) tupleExpr).getArg();
		}

		return (Join) tupleExpr;
	}
}
